4	describe("Pixel Art Scaler", () => {
5	  it("should return empty grid for empty input with scale 1", () => {
6	    expect(scalePixelArt([], 1)).toEqual([]);
7	  });
8	  it("should return exact copy of single pixel grid with scale 1", () => {
9	    expect(scalePixelArt([["A"]], 1)).toEqual([["A"]]);
10	  });
11	  it("should return exact copy of multi-pixel grid with scale 1", () => {
12	    expect(scalePixelArt([["A", "B"], ["C", "D"]], 1)).toEqual([["A", "B"], ["C", "D"]]);
13	  });
14	  it("should double a single pixel grid with scale 2", () => {
15	    expect(scalePixelArt([["A"]], 2)).toEqual([["A", "A"], ["A", "A"]]);
16	  });
17	  it("should scale a single pixel grid by factor 3", () => {
18	    expect(scalePixelArt([["X"]], 3)).toEqual([["X", "X", "X"], ["X", "X", "X"], ["X", "X", "X"]]);
19	  });
20	  it("should scale a single-row multi-pixel grid horizontally with scale 2", () => {
21	    expect(scalePixelArt([["A", "B"]], 2)).toEqual([["A", "A", "B", "B"], ["A", "A", "B", "B"]]);
22	  });
23	  it("should scale a multi-row single-column grid vertically with scale 2", () => {
24	    expect(scalePixelArt([["A"], ["B"]], 2)).toEqual([["A", "A"], ["A", "A"], ["B", "B"], ["B", "B"]]);
25	  });
