1	const repeat = <T>(value: T, times: number): T[] => Array(times).fill(value);
2	
3	export const scalePixelArt = (grid: string[][], scale: number): string[][] =>
4	  grid.flatMap((row) => repeat(row.flatMap((cell) => repeat(cell, scale)), scale));
